I & =\int_0^{\frac{\pi}{2}} \frac{\cos ^4 x+\sin x \cos ^3 x+\sin ^2 x \cos ^2 x+\sin ^3 x \cos x}{\sin ^4 x+\cos ^4 x+2 \sin x \cos ^3 x+2 \sin ^2 x \cos ^2 x+2 \sin ^3 x \cos x} d x \\
I & =\int_0^{\frac{\pi}{2}} \frac{\left(\sin x \cos ^3 x+\sin ^3 x \cos x\right)+\left(\cos ^4 x+\sin ^2 x \cos ^2 x\right)}{\sin ^4 x+\cos ^4 x+2 \sin ^2 x \cos ^2 x+\left(2 \sin x \cos ^3 x+2 \sin ^3 x \cos x\right)} d x \\
& =\int_0^{\frac{\pi}{2}} \frac{\sin x \cos x+\left(\cos ^4 x+\sin ^2 x \cos ^2 x\right)}{\sin ^4 x+\cos ^4 x+2 \sin ^2 x \cos ^2 x+2 \sin x \cos x} d x
\end{aligned}
$$

Use King and add
$$
\begin{aligned}
& 2 I=\int_0^{\frac{\pi}{2}} \frac{\sin ^4 x+\cos ^4 x+2 \sin ^2 x \cos ^2 x+2 \sin x \cos x}{\sin ^4 x+\cos ^4 x+2 \sin ^2 x \cos ^2 x+2 \sin x \cos x} d x=\frac{\pi}{2} \\
\therefore \quad I & =\frac{\pi}{4}
